@rendermode InteractiveServer
@using sv_13ae49a7733342eaae9bcc7fcd59e783.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book a Medical Appointment</h3>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* ── STEP 1: Patient Information ── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-control" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next: Choose Appointment
            </button>
        }
    </fieldset>

    @* ── STEP 2: Appointment Details ── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-control" @bind-Value="Model.Doctor" @bind:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.Date" @bind:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => Model.Date" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeSlot">Time Slot</label>
                <InputSelect id="timeSlot" class="form-control" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" rows="3" @bind-Value="Model.Reason" />
                <ValidationMessage For="() => Model.Reason" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="BackToStep1">Back</button>
            <button type="button" class="btn btn-info me-2" disabled="@isChecking" @onclick="CheckAvailability">
                @(isChecking ? "Checking..." : "Check Availability")
            </button>
            <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                @(isSubmitting ? "Booking..." : "Book Appointment")
            </button>
        </fieldset>
    }

    @if (bookingConfirmed)
    {
        <div class="alert alert-success mt-3">
            Appointment booked successfully!
        </div>
    }
</EditForm>

@code {
    private EditContext editContext = default!;
    private AppointmentModel Model { get; set; } = new();
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isChecking;
    private bool isSubmitting;
    private bool bookingConfirmed;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        customValidator?.ClearErrors();

        // Validate only step-1 fields
        var isValid = true;
        var store = new ValidationMessageStore(editContext);

        if (string.IsNullOrWhiteSpace(Model.PatientName))
        {
            store.Add(editContext.Field(nameof(Model.PatientName)), "Patient Name is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Email))
        {
            store.Add(editContext.Field(nameof(Model.Email)), "Email is required.");
            isValid = false;
        }
        else if (!new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email))
        {
            store.Add(editContext.Field(nameof(Model.Email)), "Invalid email format.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        {
            store.Add(editContext.Field(nameof(Model.Phone)), "Phone is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            store.Add(editContext.Field(nameof(Model.InsuranceProvider)), "Insurance Provider is required.");
            isValid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (isValid)
        {
            store.Clear();
            editContext.NotifyValidationStateChanged();
            showStep2 = true;
            bookingConfirmed = false;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        customValidator?.ClearErrors();
    }

    private async Task OnDoctorOrDateChanged()
    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.Date.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(
                Model.Doctor, DateOnly.FromDateTime(Model.Date.Value));
            Model.TimeSlot = string.Empty;
        }
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();
        isChecking = true;

        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email ?? "",
                Model.InsuranceProvider ?? "",
                Model.Doctor ?? "",
                Model.TimeSlot ?? "");

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private async Task HandleSubmit()
    {
        customValidator?.ClearErrors();
        isSubmitting = true;

        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email ?? "",
                Model.InsuranceProvider ?? "",
                Model.Doctor ?? "",
                Model.TimeSlot ?? "");

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            // Simulate booking
            await Task.Delay(500);
            bookingConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private sealed class AppointmentModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Patient Name is required.")]
        public string? PatientName { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Email is required.")]
        [System.ComponentModel.DataAnnotations.EmailAddress(ErrorMessage = "Invalid email format.")]
        public string? Email { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Phone is required.")]
        public string? Phone { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Insurance Provider is required.")]
        public string? InsuranceProvider { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Preferred Doctor is required.")]
        public string? Doctor { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Date is required.")]
        [FutureDate(ErrorMessage = "Date must be in the future.")]
        public DateTime? Date { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Time Slot is required.")]
        public string? TimeSlot { get; set; }

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Reason for visit is required.")]
        [System.ComponentModel.DataAnnotations.StringLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
        public string? Reason { get; set; }
    }

    private sealed class FutureDateAttribute : System.ComponentModel.DataAnnotations.ValidationAttribute
    {
        public override bool IsValid(object? value)
        {
            if (value is DateTime dt)
            {
                return dt.Date > DateTime.Today;
            }
            return false;
        }
    }
}
"}

